package com.careeros.validation.application;import org.junit.jupiter.api.Test;import java.util.*;import static org.assertj.core.api.Assertions.*;class ResumeGroundingValidatorTest{private final ResumeGroundingValidator v=new ResumeGroundingValidator();@Test void acceptsFactsPresentInMaster(){assertThat(v.validate("Built Java services improving latency by 20%",List.of("Improved Java service latency by 20%" )).valid()).isTrue();}@Test void rejectsUnknownTechnologyAndMetric(){var r=v.validate("Built Java services",List.of("Built Kubernetes platform reducing cost by 40%"));assertThat(r.valid()).isFalse();assertThat(r.warnings()).contains("Unknown technology: kubernetes","Unknown metric: 40%");}}
